import <bits/stdc++.h>
class Solution {
public:
void frontDequeue(vector<int>& nums) {
    if (nums.size() == 0) nums.push_back(0);
    nums.pop_front();
}
};
int main() {
    Solution s;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    cout << s.frontDequeue(nums) << endl;
    return 0;
}
